import{_ as a,o as n,c as s,ag as t}from"./chunks/framework.ePeAWSvT.js";const g=JSON.parse('{"title":"ASR 模块","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture/asr.md","filePath":"guide/architecture/asr.md"}'),r={name:"guide/architecture/asr.md"};function i(o,e,l,p,d,c){return n(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="asr-模块" tabindex="-1">ASR 模块 <a class="header-anchor" href="#asr-模块" aria-label="Permalink to &quot;ASR 模块&quot;">​</a></h1><p><code>src/lab/asr/</code> — 语音识别，当前支持 <strong>Sherpa-ONNX Paraformer</strong> 和 <strong>Qwen3-ASR（OpenVINO INT8）</strong> 两套引擎。</p><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>asr/</span></span>
<span class="line"><span>├── asr_base_model.py    # ASRBaseModel 抽象基类</span></span>
<span class="line"><span>├── combiner.py          # 句子合并（短间隔句子拼接）</span></span>
<span class="line"><span>├── converter.py         # 通用结果转换工具</span></span>
<span class="line"><span>├── cutter.py            # 句子切分（长停顿处拆句）</span></span>
<span class="line"><span>├── types.py             # 共享类型定义（Sentence / Word）</span></span>
<span class="line"><span>├── sherpa/</span></span>
<span class="line"><span>│   ├── engine.py        # Sherpa-ONNX Paraformer 推理引擎</span></span>
<span class="line"><span>│   ├── probe.py         # 模型探测与验证</span></span>
<span class="line"><span>│   └── utils.py         # 音频预处理工具</span></span>
<span class="line"><span>└── qwen_asr/</span></span>
<span class="line"><span>    ├── engine.py        # Qwen3-ASR OpenVINO 推理引擎（支持 0.6B / 1.7B）</span></span>
<span class="line"><span>    ├── processor.py     # 音频预处理（特征提取）</span></span>
<span class="line"><span>    └── forced_aligner.py # ForcedAligner（词级时间戳对齐，**必须配置**）</span></span></code></pre></div><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="asrbasemodel" tabindex="-1">ASRBaseModel <a class="header-anchor" href="#asrbasemodel" aria-label="Permalink to &quot;ASRBaseModel&quot;">​</a></h3><p>抽象基类，定义三个接口：</p><ul><li><code>init_model()</code> — 加载模型权重</li><li><code>reload_model()</code> — 热重载</li><li><code>forward(input_path)</code> — 推理</li></ul><p><code>sherpa/engine.py</code> 中的 Sherpa 引擎和 <code>qwen_asr/engine.py</code> 中的 Qwen3-ASR 引擎均实现此接口。</p><h3 id="sherpa-onnx-paraformer" tabindex="-1">Sherpa-ONNX Paraformer <a class="header-anchor" href="#sherpa-onnx-paraformer" aria-label="Permalink to &quot;Sherpa-ONNX Paraformer&quot;">​</a></h3><ul><li>模型：Paraformer-zh（中文）</li><li>后端：sherpa-onnx，推理延迟极低（RTF ≈ 0.007，比实时快 ~140 倍）</li><li>VAD：内置 Silero VAD，支持分段检测</li><li>配置：<code>[asr.sherpa]</code></li></ul><p><strong>为什么保留 Sherpa？</strong></p><p>Sherpa-ONNX Paraformer 在纯中文场景下速度极快。以同一句「那年长街春意正浓，策马同游」为例，Sherpa 仅需约 <strong>0.23s</strong>（CPU），而 Qwen3-ASR-1.7B 同等硬件下约需 2–3s。对于中文实时流场景，这个差距非常显著。</p><p>但 Sherpa 存在明确的语言局限性：<strong>不支持英文和日文</strong>——英文会乱码，日文会空返回。因此：</p><ul><li>纯中文场景 → 优先考虑 Sherpa（速度优先）</li><li>中英/中日混合或多语言场景 → 必须用 Qwen3-ASR</li></ul><h3 id="qwen3-asr-openvino-int8" tabindex="-1">Qwen3-ASR（OpenVINO INT8） <a class="header-anchor" href="#qwen3-asr-openvino-int8" aria-label="Permalink to &quot;Qwen3-ASR（OpenVINO INT8）&quot;">​</a></h3><ul><li>模型：Qwen3-ASR 0.6B / 1.7B，OpenVINO INT8 量化</li><li>后端：OpenVINO Runtime，CPU 推理</li><li>ForcedAligner：<strong>必须配置</strong>，提供词级时间戳对齐能力；未配置或路径不存在时启动即报错</li><li>配置：<code>[asr.qwen_asr]</code></li></ul><p>两个引擎可通过 <code>[package]</code> 开关独立启用，互不干扰，各自注册不同的 API 路由。</p><h4 id="openvino-推理延迟与预热" tabindex="-1">OpenVINO 推理延迟与预热 <a class="header-anchor" href="#openvino-推理延迟与预热" aria-label="Permalink to &quot;OpenVINO 推理延迟与预热&quot;">​</a></h4><p>OpenVINO CPU plugin 首次推理时触发 JIT kernel 编译（thread warm-up），之后进入稳定状态。以 i7-12th Gen（2022 年，CPU 散热未清灰）为例：</p><table tabindex="0"><thead><tr><th>请求</th><th>Qwen3-ASR-1.7B</th></tr></thead><tbody><tr><td>第 1 次（冷启动 JIT）</td><td>~20.7s</td></tr><tr><td>第 2 次（已预热）</td><td>~2.9s</td></tr><tr><td>第 3 次（已预热）</td><td>~2.2s</td></tr></tbody></table><p>预热完成后，推理延迟稳定在 2–3s（~10s 音频片段）。</p><p><strong>关于重启后的冷启动：</strong> 首次冷启动（JIT 编译）约 20s。启用 <code>cache_dir</code> 后，编译结果会持久化到 <code>{model_dir}/.ov_cache/</code>，后续重启可跳过 JIT 阶段，冷启动时间显著缩短。</p><p><strong>关于 idle 导致的重新预热（已修复）：</strong> 原实现使用同步 <code>request.infer()</code>，OpenVINO CPU thread pool 在约 30s 无请求后会 idle-down，下次推理重新触发预热（表现为突然变慢 10s 以上）。当前实现已改为 <code>start_async() + wait()</code> + thread pinning，worker thread 保持 event-wait 状态，<strong>idle 后不再重新预热</strong>，对实时对话场景友好。</p><h4 id="intel-gpu-推理" tabindex="-1">Intel GPU 推理 <a class="header-anchor" href="#intel-gpu-推理" aria-label="Permalink to &quot;Intel GPU 推理&quot;">​</a></h4><p>设置 <code>device = &quot;GPU&quot;</code> 可启用 Intel GPU 加速推理。</p><p><strong>支持的硬件：</strong></p><ul><li>Intel HD/UHD Graphics（第 6 代 Core 及以上，约 2015 年起）</li><li>Intel Iris Xe Graphics</li><li>Intel Arc 独显（全系）</li></ul><p><strong>驱动要求：</strong></p><ul><li><strong>Windows</strong>：通常随 Intel 显卡驱动内置，无需额外安装。</li><li><strong>Linux</strong>：需安装 OpenCL runtime：<code>sudo apt install intel-opencl-icd</code></li></ul><p><strong>GPU 缓存目录：</strong> GPU 编译缓存默认存储在 <code>{model_dir}/.ov_cache_gpu/</code>，可通过 <code>gpu_cache_dir</code> 自定义路径。</p><p><strong>配置示例：</strong></p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">asr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qwen_asr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">device = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;GPU&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gpu_cache_dir = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 空 = 使用默认路径</span></span></code></pre></div><h4 id="长音频-benchmark-example2-m4a-4m-13s-中英混合" tabindex="-1">长音频 benchmark（example2.m4a，~4m 13s，中英混合） <a class="header-anchor" href="#长音频-benchmark-example2-m4a-4m-13s-中英混合" aria-label="Permalink to &quot;长音频 benchmark（example2.m4a，~4m 13s，中英混合）&quot;">​</a></h4><p>硬件：i7-12th Gen（2022 笔记本），ForcedAligner 放在 GPU 上跑</p><table tabindex="0"><thead><tr><th>Metric</th><th>数值</th></tr></thead><tbody><tr><td>总耗时</td><td>68.8s</td></tr><tr><td>ASR 总计</td><td>59.3s（28 个 chunk）</td></tr><tr><td>Aligner 总计</td><td>6.7s（GPU）</td></tr><tr><td>平均每 chunk（~10s 音频）</td><td>~2.5s ASR + ~0.3s align</td></tr></tbody></table><p>典型 chunk 耗时：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[226910,236910] dur=10000ms  asr=3.257s  align=0.330s</span></span>
<span class="line"><span>[236910,246910] dur=10000ms  asr=2.498s  align=0.296s</span></span>
<span class="line"><span>[246910,253454] dur=6544ms   asr=1.589s  align=0.072s</span></span></code></pre></div><blockquote><p><strong>0.6B vs 1.7B 速度差</strong>：以同一段长音频（~4m 13s）为例，0.6B 总 ASR 耗时约 <strong>40s</strong>，1.7B 约 <strong>60s</strong>，差距约 1.5×，小于参数量比例（1.7B / 0.6B ≈ 2.8×）。推测原因是 audio encoder（两个模型共享相近架构）的耗时在 per-chunk 中占比较高，decoder 参数量的差异被稀释了。</p></blockquote><h4 id="forcedaligner-放-gpu-的收益" tabindex="-1">ForcedAligner 放 GPU 的收益 <a class="header-anchor" href="#forcedaligner-放-gpu-的收益" aria-label="Permalink to &quot;ForcedAligner 放 GPU 的收益&quot;">​</a></h4><p>ForcedAligner CPU 推理延迟与 ASR 本身相当，严重拖慢整体速度。放到 GPU（<code>forced_aligner_device = &quot;cuda&quot;</code>）后，align 耗时降至 0.07–0.33s，几乎可以忽略不计。</p><p>建议：有独显的机器一律把 ForcedAligner 放 GPU。</p><h4 id="关于-openvino-intel-gpu-推理-device-gpu" tabindex="-1">关于 OpenVINO Intel GPU 推理（device = &quot;GPU&quot;） <a class="header-anchor" href="#关于-openvino-intel-gpu-推理-device-gpu" aria-label="Permalink to &quot;关于 OpenVINO Intel GPU 推理（device = &quot;GPU&quot;）&quot;">​</a></h4><p>OpenVINO 支持将推理调度到 Intel GPU（iGPU 核显或 Arc 独显），但<strong>对 Qwen3-ASR 场景实测性能反而更差</strong>，不建议使用。</p><p><strong>原因：</strong></p><p>Qwen3-ASR decoder 是逐 token autoregressive 推理，每次 decode 只处理 1 个 token，单次计算量极小。GPU 的优势在大 batch 和大矩阵，但此场景下：</p><ul><li>每次推理数据量极小，CPU → GPU 显存的调度开销远大于计算收益</li><li>iGPU（核显）EU 数量有限，并行度优势无法发挥</li><li>实测同一硬件（i7-12th Gen）CPU RTF ≈ <strong>0.3</strong>，GPU RTF ≈ <strong>1.0</strong>（勉强实时）</li></ul><p><strong>结论：</strong></p><table tabindex="0"><thead><tr><th>推理设备</th><th>场景</th><th>建议</th></tr></thead><tbody><tr><td><code>device = &quot;CPU&quot;</code></td><td>Qwen3-ASR decoder（autoregressive）</td><td>✅ 推荐，默认值</td></tr><tr><td><code>device = &quot;GPU&quot;</code></td><td>Qwen3-ASR decoder</td><td>❌ 实测更慢，不建议</td></tr><tr><td><code>forced_aligner_device = &quot;cuda&quot;</code></td><td>ForcedAligner（PyTorch）</td><td>✅ 强烈推荐，收益显著</td></tr></tbody></table><p>如果想压榨 GPU 利用率，正确姿势是把 <strong>ForcedAligner 放到 CUDA GPU</strong>，而不是把 OpenVINO 推理切到 Intel GPU。</p><h3 id="句子后处理" tabindex="-1">句子后处理 <a class="header-anchor" href="#句子后处理" aria-label="Permalink to &quot;句子后处理&quot;">​</a></h3><p>ASR 输出的原始句子需要经过后处理才能用于字幕显示：</p><ol><li><strong>Cutter</strong> — 根据 <code>cut_line</code>（停顿阈值）将长句拆成短句</li><li><strong>Combiner</strong> — 根据 <code>combine_line</code> 将间隔过短的句子合并</li></ol><p>两者互为反向操作，建议只启用其中一个。如果同时启用，需要 <code>combine_line &gt; cut_line</code>。</p><h3 id="数据结构" tabindex="-1">数据结构 <a class="header-anchor" href="#数据结构" aria-label="Permalink to &quot;数据结构&quot;">​</a></h3><p>ASR 结果统一为 <code>Sentence</code> 结构（定义在 <code>types.py</code>），包含：</p><ul><li>文本内容</li><li>词级时间戳（<code>Word</code> 列表）</li><li>起止时间</li></ul><p>各引擎的内部输出均会转换为统一的 <code>Sentence</code> 格式，供上层逻辑消费。</p><h2 id="与其他模块的关系" tabindex="-1">与其他模块的关系 <a class="header-anchor" href="#与其他模块的关系" aria-label="Permalink to &quot;与其他模块的关系&quot;">​</a></h2><ul><li><strong>api/routes/asr_sherpa.py</strong> 暴露 Sherpa-ONNX HTTP 接口</li><li><strong>api/routes/asr_qwen.py</strong> 暴露 Qwen3-ASR HTTP 接口</li><li><strong>api/routes/asr_reload.py</strong> 暴露热重载接口</li><li><strong>api/logic/sherpa_asr.py</strong> / <strong>api/logic/qwen_asr.py</strong> 封装推理逻辑</li><li><strong>api/clients/asr_client.py</strong> 提供客户端封装</li></ul>`,60)])])}const u=a(r,[["render",i]]);export{g as __pageData,u as default};
